import { useEffect, useState } from "react";
import API from "../../api/axios";
import {
  Button,
  TextField,
  Typography,
  Box,
  Card,
  CardContent,
  IconButton,
  InputAdornment,
} from "@mui/material";
import { Visibility, VisibilityOff } from "@mui/icons-material";
import { useNavigate } from "react-router-dom";

export default function Projects() {
  const navigate = useNavigate();

  const [projects, setProjects] = useState([]);
  const [showPassword, setShowPassword] = useState(false);

  const [projectForm, setProjectForm] = useState({
    name: "",
    description: "",
    start_date: "",
    end_date: "",
  });

  const [userForm, setUserForm] = useState({
    username: "",
    password: "",
    project_id: "",
  });

  // 🔥 FETCH PROJECTS
  const fetchProjects = async () => {
    try {
      const res = await API.get("projects/");
      setProjects(res.data);
    } catch (err) {
      console.log("ERROR:", err);
    }
  };

  useEffect(() => {
    fetchProjects();
  }, []);

  // 🔥 CREATE PROJECT
  const createProject = async () => {
    try {
      await API.post("projects/create/", projectForm);
      alert("Project Created ✅");
      fetchProjects();
    } catch (err) {
      console.log(err);
    }
  };

  // 🔥 CREATE USER
  const createProjectUser = async () => {
    try {
      await API.post("create-user/", userForm);
      alert("User Added ✅");
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <Box
      sx={{
        display: "flex",
        gap: 4,
        flexWrap: "wrap",
        p: 3,
      }}
    >
      {/* LEFT CARD */}
      <Card
        sx={{
          flex: 1,
          minWidth: 320,
          p: 2,
          borderRadius: 4,
          background: "linear-gradient(135deg, #1e3c72, #2a5298)",
          color: "#fff",
        }}
      >
        <CardContent>
          <Typography variant="h6">Create Project</Typography>

          <TextField
            fullWidth
            label="Project Name"
            margin="normal"
            InputLabelProps={{ style: { color: "#fff" } }}
            sx={{ input: { color: "#fff" } }}
            onChange={(e) =>
              setProjectForm({ ...projectForm, name: e.target.value })
            }
          />

          <TextField
            fullWidth
            label="Description"
            margin="normal"
            InputLabelProps={{ style: { color: "#fff" } }}
            sx={{ input: { color: "#fff" } }}
            onChange={(e) =>
              setProjectForm({
                ...projectForm,
                description: e.target.value,
              })
            }
          />

          <TextField
            fullWidth
            type="date"
            margin="normal"
            InputLabelProps={{ shrink: true }}
            onChange={(e) =>
              setProjectForm({
                ...projectForm,
                start_date: e.target.value,
              })
            }
          />

          <TextField
            fullWidth
            type="date"
            margin="normal"
            InputLabelProps={{ shrink: true }}
            onChange={(e) =>
              setProjectForm({
                ...projectForm,
                end_date: e.target.value,
              })
            }
          />

          <Button
            fullWidth
            variant="contained"
            sx={{ mt: 2 }}
            onClick={createProject}
          >
            CREATE PROJECT
          </Button>
        </CardContent>
      </Card>

      {/* RIGHT CARD */}
      <Card
        sx={{
          flex: 1,
          minWidth: 320,
          p: 3,
          borderRadius: 4,
          background: "linear-gradient(135deg, #0f2027, #203a43)",
          color: "#fff",
        }}
      >
        <CardContent>
          <Typography variant="h6" textAlign="center">
            Create Project User
          </Typography>

          <TextField
            fullWidth
            label="Username"
            margin="normal"
            InputLabelProps={{ style: { color: "#fff" } }}
            sx={{ input: { color: "#fff" } }}
            onChange={(e) =>
              setUserForm({ ...userForm, username: e.target.value })
            }
          />

          <TextField
            fullWidth
            label="Password"
            type={showPassword ? "text" : "password"}
            margin="normal"
            InputLabelProps={{ style: { color: "#fff" } }}
            sx={{ input: { color: "#fff" } }}
            onChange={(e) =>
              setUserForm({ ...userForm, password: e.target.value })
            }
            InputProps={{
              endAdornment: (
                <InputAdornment position="end">
                  <IconButton onClick={() => setShowPassword(!showPassword)}>
                    {showPassword ? <VisibilityOff /> : <Visibility />}
                  </IconButton>
                </InputAdornment>
              ),
            }}
          />

          <Button
            fullWidth
            variant="contained"
            sx={{ mt: 3 }}
            onClick={createProjectUser}
          >
            CREATE USER
          </Button>
        </CardContent>
      </Card>

      {/* VIEW BUTTON */}
      <Box width="100%" textAlign="center" mt={4}>
        <Button
          variant="contained"
          onClick={() => navigate("/admin/projects/list")}
        >
          VIEW PROJECT LIST
        </Button>
      </Box>
    </Box>
  );
}
